parameters.jsCode:
// Load Episodic Memory
return [{
  json: {
    stage: "Load Episodic Memory",
    description: "Reads episodes.json — full history of past iterations",
    file: "memory/episodes.json",
    module: "memory/memory_manager.py"
  }
}];

// Reflection Engine
return [{
  json: {
    stage: "Reflection Engine",
    description: "Analyzes past episodes to extract behavioral insights and failure patterns",
    module: "brain/reflection.py",
    output: "insights[]"
  }
}];

// Mutation Engine
return [{
  json: {
    stage: "Mutation Engine",
    description: "Generates targeted mutation proposal based on reflection insights",
    module: "brain/mutation_engine.py",
    output: "mutation_proposal"
  }
}];

// Safety Guard
const mutation = $input.first().json.output;
const blocked = false; // simulate

return [{
  json: {
    stage: "Safety Guard",
    description: "Validates mutation — blocks unsafe patterns before touching filesystem",
    module: "runtime/safety_guard.py",
    mutation_safe: !blocked,
    action: blocked ? "BLOCKED → Skip Iteration" : "PASS → Continue"
  }
}];

// Blocked path
return [{
  json: {
    stage: "BLOCKED",
    description: "Mutation rejected by Safety Guard. Iteration skipped.",
    result: "skip"
  }
}];

// Version Manager — Create Snapshot
const ts = new Date().toISOString().replace(/[-:.TZ]/g, '').slice(0,15);
return [{
  json: {
    stage: "Version Manager",
    description: "Creates timestamped snapshot of brain/ before applying mutation",
    module: "runtime/version_manager.py",
    snapshot: `versions/snapshot_${ts}/`
  }
}];

// Self-Editor — Apply Mutation
return [{
  json: {
    stage: "Self-Editor",
    description: "Applies mutation to brain/planner.py or configs/planner.json",
    module: "brain/self_editor.py",
    targets: ["brain/planner.py", "configs/planner.json"]
  }
}];

// Benchmark Runner
return [{
  json: {
    stage: "Benchmark Runner",
    description: "Executes standardized benchmark tasks and collects results",
    module: "runtime/benchmark_runner.py",
    tasks_source: "tasks/benchmark_tasks.py"
  }
}];

// Adaptive Evaluator
const score = Math.random() * 0.5 + 0.5; // simulate 0.5–1.0
return [{
  json: {
    stage: "Adaptive Evaluator",
    description: "Scores iteration with context-aware metrics + repetition penalty",
    module: "brain/adaptive_evaluator.py",
    score: parseFloat(score.toFixed(2)),
    threshold: 0.6,
    accepted: score >= 0.6
  }
}];

// Accept Generation
return [{
  json: {
    stage: "Accept Generation",
    description: "Score passed threshold. Mutation kept. Self-model updated with new strength.",
    module: "memory/self_model_manager.py",
    action: "update_strength",
    result: "ACCEPTED ✓"
  }
}];

// Reject + Rollback
return [{
  json: {
    stage: "Reject + Rollback",
    description: "Score below threshold. Rollback to last snapshot. Self-model updated with weakness.",
    module: "runtime/rollback_manager.py",
    action: "rollback + update_weakness",
    result: "REJECTED ✗ → ROLLED BACK"
  }
}];

// Memory Manager — Store Episode
return [{
  json: {
    stage: "Memory Manager",
    description: "Stores full episode (mutation, score, snapshot ref, evaluation) to episodes.json",
    module: "memory/memory_manager.py",
    output: "memory/episodes.json"
  }
}];

// Meta Reasoner
return [{
  json: {
    stage: "Meta Reasoner",
    description: "Cross-iteration analysis of full evolution history. Surfaces patterns and hypotheses.",
    module: "brain/meta_reasoner.py",
    output: "insights[], hypotheses[]"
  }
}];

// Evolution Complete
return [{
  json: {
    stage: "END",
    description: "One evolution iteration complete. Loop continues for N iterations.",
    next: "Next Iteration or END"
  }
}];
